using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummaryService summaryService) : ControllerBase
{
    private const int DefaultMaxSentences = 3;

    /// <summary>
    /// Accepts a document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var maxSentences = request.MaxSentences ?? DefaultMaxSentences;
        var summary = summaryService.Summarize(request.DocumentText, maxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

